const inputData = $input.item.json;
const fechaRaw = inputData.fecha.replace(/\//g, '-');
const horaRaw = inputData.hora;
const partes = fechaRaw.split('-').map(Number);
let d, m, y;
if (partes[0] > 1000) { [y, m, d] = partes; }
else if (partes[2] > 1000) { [d, m, y] = partes; }
else { [d, m, y] = partes; y += 2000; }
const horaPartes = horaRaw.toString().replace(':','.').split('.');
const horas = parseInt(horaPartes[0]);
const minutos = parseInt(horaPartes[1] || '0');
const fechaObj = new Date(y, m-1, d, horas, minutos, 0);
const fechaFin = new Date(fechaObj.getTime() + 90*60000);
const toISO = (date) => {
  const pad = n => String(n).padStart(2,'0');
  return `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}:00-03:00`;
};
const fechaFormateada = `${String(d).padStart(2,'0')}/${String(m).padStart(2,'0')}/${y}`;
const horaFormateada = `${String(horas).padStart(2,'0')}:${String(minutos).padStart(2,'0')}`;
return { ...inputData, fecha_hora_iso_start: toISO(fechaObj), fecha_hora_iso_end: toISO(fechaFin), fecha_formateada: fechaFormateada, hora_formateada: horaFormateada };

const itemsCalendario = $input.all();
const eventos = (itemsCalendario.length > 0 && itemsCalendario[0].json.id) ? itemsCalendario.map(i => i.json) : [];
const datosReserva = $node['When Executed by Another Workflow'].json;
const eventosPorCancha = {};
const hasTorneo = {};
for (const ev of eventos) {
  const match = (ev.summary || '').match(/N°(\d+)/);
  if (match) {
    const c = match[1];
    eventosPorCancha[c] = true;
    if ((ev.summary || '').toLowerCase().includes('torneo')) hasTorneo[c] = true;
  }
}
const todas = ['1','2','3','4'];
const ocupadas = Object.keys(eventosPorCancha);
const disponibles = todas.filter(c => !ocupadas.includes(c));
const canchaSolicitada = String(datosReserva.cancha);
const canchaSolicitadaLibre = !ocupadas.includes(canchaSolicitada);
return { ...datosReserva, fecha_hora_iso_start: $node['Convertir fecha'].json.fecha_hora_iso_start, fecha_hora_iso_end: $node['Convertir fecha'].json.fecha_hora_iso_end, fecha_formateada: $node['Convertir fecha'].json.fecha_formateada, hora_formateada: $node['Convertir fecha'].json.hora_formateada, canchas_disponibles: disponibles, cancha_solicitada: canchaSolicitada, cancha_solicitada_libre: canchaSolicitadaLibre, cancha_final: canchaSolicitadaLibre ? canchaSolicitada : (disponibles[0] || null), mensaje_estado: canchaSolicitadaLibre ? 'OK' : 'OCUPADA', motivo_bloqueo: hasTorneo[canchaSolicitada] ? 'torneo' : null, hay_torneo_activo: Object.keys(hasTorneo).length > 0, canchas_en_torneo: Object.keys(hasTorneo) };

const datosReserva = $node['Canchas disponibles'].json;
const disponibles = datosReserva.canchas_disponibles;
const hayDisponibilidadAhora = disponibles.length > 0;
return {
  status: 'cancha_ocupada',
  cancha_solicitada: datosReserva.cancha_solicitada,
  canchas_disponibles: disponibles,
  hay_otras_canchas: hayDisponibilidadAhora,
  canchas_libres_proximas: disponibles,
  mensaje_para_agente: hayDisponibilidadAhora
    ? `La cancha ${datosReserva.cancha_solicitada} está ocupada. Canchas disponibles: ${disponibles.join(', ')}. Consultá al cliente si quiere alguna de estas.`
    : `La cancha ${datosReserva.cancha_solicitada} está ocupada y no hay otras canchas disponibles para ese horario.`
};

return {
  status: 'cancha_ocupada',
  error: 'La cancha solicitada ya tiene una reserva en ese horario.',
  opciones_disponibles: {
    canchas_libres: $node['Sugerir alternativa'].json.canchas_libres_proximas,
    mensaje_sugerido: $input.first().json.mensaje_para_agente
  }
};

